const base64Audio = $('HTTP Request').first().json.audios[0];

const token = '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';
const username = 'tanishsaini626-prog';
const repo = 'doctor-bot-audio';
const filename = 'greeting.wav';

// First check if file exists to get SHA
let sha = undefined;
try {
  const checkFile = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://api.github.com/repos/${username}/${repo}/contents/${filename}`,
    headers: {
      'Authorization': `token ${token}`,
      'User-Agent': 'n8n'
    }
  });
  sha = checkFile.sha;
} catch(e) {
  // File doesn't exist yet, sha stays undefined
}

const body = {
  message: 'Update audio',
  content: base64Audio
};
if (sha) body.sha = sha;

await this.helpers.httpRequest({
  method: 'PUT',
  url: `https://api.github.com/repos/${username}/${repo}/contents/${filename}`,
  headers: {
    'Authorization': `token ${token}`,
    'Content-Type': 'application/json',
    'User-Agent': 'n8n'
  },
  body: body,
  json: true
});

const audioUrl = `https://cdn.jsdelivr.net/gh/${username}/${repo}@main/${filename}`;
return [{ json: { audioUrl: audioUrl } }];
